#include<bits/stdc++.h>
using namespace std;
char a[100010];
int main()
{
	//freopen("string.in","r",stdin);
	//freopen("string.out","w",stdout);
	int t;
	scanf("%d",&t);
	while(t--)
	{
		int len=0,cnt0=0,cnt1=0,left0=0,left1=0;
		scanf("%s",a);
		len=strlen(a);
		for(int i=0;i<len;i++)
		{
			if(a[i]=='O')
			{
				cnt0++;
			}
			else
			{
				cnt1++;
			}
		}
		int ans=min(cnt1,cnt0);
		for(int i=0;i<len;i++)
		{
			if(a[i]=='O')
			{
				left0++;
				cnt0--;
			}
			else
			{
				left1++;
				cnt1--;
			}
			ans=min(ans,min(left0+cnt1,left1+cnt0));
		}
		printf("%d\n",ans);
	}
	return 0;
}
